<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --auth-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bearer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
